window.ipubGetCeTemplates = function (publisher) {
  if (!publisher) return [];
  // "Brill-Book" UI label -> "BrillBook" data key (Excel sheet name).
  var key = (publisher === "Brill-Book") ? "BrillBook" : publisher;
  var list = (window.IPUB_CE_TEMPLATES && window.IPUB_CE_TEMPLATES[key]) || [];
  return list.slice();
};
